import{_ as s,C as t,o as p,c as h,j as a,a as i,E as n,a3 as m}from"./chunks/framework.CVjg771q.js";const P=JSON.parse('{"title":"了凡四训·谦德之效","description":"第四篇，满招损谦受益——惟谦受福。","frontmatter":{"title":"了凡四训·谦德之效","description":"第四篇，满招损谦受益——惟谦受福。","category":"guide","aliases":["谦德之效","了凡四训第四篇"],"source":["《了凡四训》"]},"headers":[],"relativePath":"lizhimingde/liaofan-sixun/chapter-04.md","filePath":"lizhimingde/liaofan-sixun/chapter-04.md","lastUpdated":1781102614000}'),c={name:"lizhimingde/liaofan-sixun/chapter-04.md"};function u(x,e,g,f,_,b){const r=t("DaoReadingPrelude"),o=t("DaoOriginalReading"),l=t("DaoLineGuide"),d=t("DaoKeywordCards");return p(),h("div",null,[e[0]||(e[0]=a("h1",{id:"了凡四训·谦德之效",tabindex:"-1"},[i("了凡四训·谦德之效 "),a("a",{class:"header-anchor",href:"#了凡四训·谦德之效","aria-label":'Permalink to "了凡四训·谦德之效"'},"​")],-1)),n(r,{title:"满招损，谦受益——惟谦受福",summary:"谦德之效是了凡四训最后一篇。了凡以自身见闻说明：谦虚不只是道德修养，更是实实在在的受福之基。举头三尺有神明，趋吉避凶断然由我——而谦虚正是打开这道门的第一把钥匙。",points:[{label:"总纲",text:"满招损，谦受益——六爻皆吉，惟谦而已。"},{label:"实证",text:"数例见闻——谦虚之人，天地鬼神犹将佑之。"},{label:"归根",text:"有志於功名者必得功名——立志如树之有根。"}],hint:"这篇虽短，却是全书的精神落点——改过、积善之后，最终要以谦德来涵养这一切。"}),e[1]||(e[1]=a("h2",{id:"【原典层】原文",tabindex:"-1"},[i("【原典层】原文 "),a("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),n(o,{tone:"ink",density:"comfortable",defaultMode:"regular",modeSwitch:!1,paragraphs:["易曰：天道亏盈而益谦；地道变盈而流谦；鬼神害盈而福谦；人道恶盈而好谦。是故谦之一卦，六爻皆吉。书曰：满招损，谦受益。予屡同诸公应试，每见寒士将达，必有一段谦光可掬。","辛未计偕，我嘉善同袍凡十人，惟丁敬宇宾，年最少，极其谦虚。予告费锦坡曰：此兄今年必第。费曰：何以见之？予曰：惟谦受福。兄看十人中，有恂恂款款，不敢先人，如敬宇者乎？有恭敬顺承，小心谦畏，如敬宇者乎？有受侮不答，闻谤不辩，如敬宇者乎？人能如此，即天地鬼神，犹将佑之，岂有不发者？及开榜，丁果中式。","丁丑在京，与冯开之同处，见其虚己敛容，大变其幼年之习。李霁岩直谅益友，时面攻其非，但见其平怀顺受，未尝有一言相报。予告之曰：福有福始，祸有祸先，此心果谦，天必相之，兄今年决第矣。已而果然。","赵裕峰，光远，山东冠县人，童年举於乡，久不第。其父为嘉善三尹，随之任。慕钱明吾，而执文见之，明吾悉抹其文，赵不惟不怒，且心服而速改焉。明年，遂登第。","壬辰岁，予入觐，晤夏建所，见其人气虚意下，谦光逼人，归而告友人曰：凡天将发斯人也，未发其福，先发其慧；此慧一发，则浮者自实，肆者自敛；建所温良若此，天启之矣。及开榜，果中式。","江阴张畏岩，积学工文，有声艺林。甲午，南京乡试，寓一寺中，揭晓无名，大骂试官，以为眯目。时有一道者，在傍微笑，张遽移怒道者。道者曰：相公文必不佳。张怒曰：汝不见我文，乌知不佳？道者曰：闻作文，贵心气和平，今听公骂詈，不平甚矣，文安得工？张不觉屈服，因就而请教焉。道者曰：中全要命；命不该中，文虽工，无益也。须自己做个转变。张曰：既是命，如何转变？道者曰：造命者天，立命者我；力行善事，广积阴德，何福不可求哉？张曰：我贫士，何能为？道者曰：善事阴功，皆由心造，常存此心，功德无量，且如谦虚一节，并不费钱，你如何不自反而骂试官乎？张由此折节自持，善日加修，德日加厚。丁酉，梦至一高房，得试录一册，中多缺行。问旁人，曰：此今科试录。问：何多缺名？曰：科第阴间三年一考较，须积德无咎者，方有名。如前所缺，皆系旧该中式，因新有薄行而去之者也。后指一行云：汝三年来，持身颇慎，或当补此，幸自爱。是科果中一百五名。","由此观之，举头三尺，决有神明；趋吉避凶，断然由我。须使我存心制行，毫不得罪於天地鬼神，而虚心屈己，使天地鬼神，时时怜我，方有受福之基。彼气盈者，必非远器，纵发亦无受用。稍有识见之士，必不忍自狭其量，而自拒其福也，况谦则受教有地，而取善无穷，尤修业者所必不可少者也。","古语云：有志於功名者，必得功名；有志於富贵者，必得富贵。人之有志，如树之有根，立定此志，须念念谦虚，尘尘方便，自然感动天地，而造福由我。今之求登科第者，初未尝有真志，不过一时意兴耳；兴到则求，兴阑则止。孟子曰：王之好乐甚，齐其庶几乎？予於科名亦然。"]}),n(l,{lines:[{text:"易曰：天道亏盈而益谦；地道变盈而流谦；鬼神害盈而福谦；人道恶盈而好谦。是故谦之一卦，六爻皆吉。",tone:"总纲 · 天地皆归谦",guide:"开篇从天、地、鬼神、人四个维度讲同一个道理：满则招损，谦则受益。易卦中唯有谦卦六爻皆吉——连乾卦都有亢龙有悔，但谦卦从初爻到上爻，没有一爻是凶的。"},{text:"予屡同诸公应试，每见寒士将达，必有一段谦光可掬。",tone:"观察 · 谦光",guide:"了凡用自己多年的观察提出一个可验证的规律：那些即将发迹的人，往往不是最聪明的，而是最谦虚的。他举了丁敬宇、冯开之、赵裕峰、夏建所、张畏岩五人的例子——每一个都是因谦虚而受益。"},{text:"造命者天，立命者我；力行善事，广积阴德，何福不可求哉？",tone:"呼应 · 回扣第一篇",guide:"张畏岩故事中的道者所说，是全书第一段命由我作，福自己求的回响。谦德之效不是孤立的——它和立命之学是同一件事的两个侧面：立命是改命的原理，谦虚是改命的姿态。"},{text:"人之有志，如树之有根，立定此志，须念念谦虚，尘尘方便，自然感动天地，而造福由我。",tone:"收束 · 立志如根",guide:"全篇最后归到一个字：志。有志的人才有根，有根才能立住。而谦虚就是保持这根不被骄傲腐蚀的土壤。全书的最后一句话落在科名上，但它真正说的早已超出了科名。"}]}),e[2]||(e[2]=a("h2",{id:"【原典层】字词释义",tabindex:"-1"},[i("【原典层】字词释义 "),a("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),n(d,{items:[{term:"谦卦",pinyin:["qiān","guà"],meaning:"易经第十五卦，卦象为地山谦（上坤下艮）。六十四卦中唯一六爻皆吉的卦——从初爻到上爻，没有一爻是凶的，因为谦虚本身就已经避开了所有招祸的根源。"},{term:"谦光",pinyin:["qiān","guāng"],meaning:"了凡自创的词。指一个人因内心谦虚而自然流露出的柔和光芒——不是刻意表现的低调，而是一种不敢先人平怀顺受的气质。"},{term:"恂恂款款",pinyin:["xún","xún","kuǎn","kuǎn"],meaning:"诚实、谨慎、不张扬的样子。了凡用这四个字形容丁敬宇的谦虚之态——不是自卑，而是一种自然而然的收敛。"},{term:"折节自持",pinyin:["zhé","jié","zì","chí"],meaning:"改变过去的行为方式，严格约束自己。指张畏岩被道者点醒后，从大骂试官变为善日加修，德日加厚。"},{term:"虚心屈己",pinyin:["xū","xīn","qū","jǐ"],meaning:"放下身段，不强出头。不是懦弱，而是使天地鬼神时时怜我的受福之基——你越不争，天地越帮你。"}]}),e[3]||(e[3]=m('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一篇在说什么" tabindex="-1">象：这一篇在说什么 <a class="header-anchor" href="#象-这一篇在说什么" aria-label="Permalink to &quot;象：这一篇在说什么&quot;">​</a></h3><p>谦德之效是四训的最后收官。前面三篇讲了命可以改怎么改过怎么积善，到这一篇，了凡回来说：别骄傲。改过和积善如果带来了优越感，那你之前的功夫就全白费了。</p><p>他举了五个人——因谦虚考中进士的、因谦虚而中举的——不是讲玄理，就是讲自己亲眼看到的事实。每见寒士将达，必有一段谦光可掬——这句话把谦虚从道德修为还原成了一种可观察的征兆。</p><h3 id="理-为什么这一篇重要" tabindex="-1">理：为什么这一篇重要 <a class="header-anchor" href="#理-为什么这一篇重要" aria-label="Permalink to &quot;理：为什么这一篇重要&quot;">​</a></h3><p>这一篇重要在它的位置——放在最后一篇。如果第一篇告诉你命由我作，第二篇教你改过，第三篇教你积善，似乎整个体系已经很自足了。但了凡在这里加了一笔：你做了这么多，会不会开始觉得自己了不起？</p><p>谦虚不是外加的美德，它是前面一切努力的保障。一个骄傲的人改不了过（因为不觉得自己有错），也积不了善（因为做一点就觉得够了）。所以谦德之效不是附录，是保险锁。</p><p>易卦中唯有谦卦六爻皆吉。这不是巧合——因为谦虚的人已经预先扣掉了所有招祸的诱因。</p><h3 id="用-今天怎么进入这一篇" tabindex="-1">用：今天怎么进入这一篇 <a class="header-anchor" href="#用-今天怎么进入这一篇" aria-label="Permalink to &quot;用：今天怎么进入这一篇&quot;">​</a></h3><p>这篇最实际的练习是：当你做了一件好事、取得了一点成绩、被别人夸了一句之后，观察自己内心的第一个反应。是我真厉害还是还有很多要学的？</p><p>另外一个练习是：下次和人争论时，先停下来问自己——我是在捍卫真理，还是在捍卫自己的面子？如果是后者，了凡会说：你正在用自己的骄傲，一点点消耗自己积的福。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>谦虚不是自卑，也不是故作低调。谦虚是你知道自己做的那点事在更大的格局里不算什么，所以你不会因为一句夸奖就飘起来，也不会因为一句批评就垮下去。</p><p>了凡把谦虚抬到一个很高的位置——它和命运连在一起。骄傲的人，命运不会好；不是因为天在惩罚他，而是因为他自己把能变好的路全堵死了。一个不觉得自己有错的人不可能改过，一个觉得自己做得够多的人不可能继续积善。</p><p>所以谦虚的本质，是给自己的成长留出空间。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>待整理。</p>',17))])}const k=s(c,[["render",u]]);export{P as __pageData,k as default};
